package com.example.bankapp;

import android.database.sqlite.SQLiteDatabase;

import java.util.UUID;

public final class TransactionProcessor {
    private final AccountRepository accountRepository;
    private final TransactionRepository transactionRepository;
    private final AppDatabase db;

    public TransactionProcessor(AccountRepository accountRepository,
                                TransactionRepository transactionRepository,
                                AppDatabase db) {
        this.accountRepository = accountRepository;
        this.transactionRepository = transactionRepository;
        this.db = db;
    }

    public Result transfer(String fromAccountId, String toAccountId, long amountMinor, String currency, String note) {
        if (fromAccountId == null || toAccountId == null) return Result.error("Invalid account");
        if (fromAccountId.equals(toAccountId)) return Result.error("Accounts must differ");
        if (amountMinor <= 0) return Result.error("Amount must be > 0");
        if (currency == null || currency.trim().isEmpty()) return Result.error("Invalid currency");

        SQLiteDatabase w = db.getWritableDatabase();
        String txId = UUID.randomUUID().toString();
        long now = System.currentTimeMillis();

        w.beginTransaction();
        try {
            Account from = accountRepository.getById(fromAccountId);
            Account to = accountRepository.getById(toAccountId);
            if (from == null || to == null) {
                return Result.error("Account not found");
            }
            if (!currency.equals(from.currency) || !currency.equals(to.currency)) {
                return Result.error("Currency mismatch");
            }
            if (from.balanceMinor < amountMinor) {
                BankTransaction failed = new BankTransaction(txId, fromAccountId, toAccountId, amountMinor, currency, note,
                        BankTransaction.Status.FAILED, now);
                transactionRepository.insert(w, failed);
                w.setTransactionSuccessful();
                return Result.error("Insufficient funds");
            }

            BankTransaction pending = new BankTransaction(txId, fromAccountId, toAccountId, amountMinor, currency, note,
                    BankTransaction.Status.PENDING, now);
            transactionRepository.insert(w, pending);

            long newFromBal = from.balanceMinor - amountMinor;
            long newToBal = to.balanceMinor + amountMinor;

            accountRepository.updateBalanceMinor(w, fromAccountId, newFromBal, now);
            accountRepository.updateBalanceMinor(w, toAccountId, newToBal, now);

            transactionRepository.updateStatus(w, txId, BankTransaction.Status.POSTED);

            w.setTransactionSuccessful();
            return Result.success(txId);
        } catch (Exception e) {
            return Result.error("Transfer failed");
        } finally {
            w.endTransaction();
        }
    }

    public static final class Result {
        public final boolean ok;
        public final String transactionId;
        public final String error;

        private Result(boolean ok, String transactionId, String error) {
            this.ok = ok;
            this.transactionId = transactionId;
            this.error = error;
        }

        public static Result success(String txId) { return new Result(true, txId, null); }
        public static Result error(String msg) { return new Result(false, null, msg); }
    }
}

package com.example.bankapp;

import java.text.NumberFormat;
import java.util.Currency;
import java.util.Locale;

public final class MoneyFormatter {
    private MoneyFormatter() {}

    public static String formatMinor(String currencyCode, long minorAmount) {
        Currency c = Currency.getInstance(currencyCode);
        int fraction = c.getDefaultFractionDigits();
        NumberFormat nf = NumberFormat.getCurrencyInstance(Locale.getDefault());
        nf.setCurrency(c);
        double major = minorAmount / Math.pow(10, Math.max(fraction, 0));
        return nf.format(major);
    }
}

package com.example.bankapp.ui;

import android.app.Activity;
import android.content.Intent;
import android.os.AsyncTask;
import android.os.Bundle;
import android.view.View;
import android.widget.AdapterView;
import android.widget.ArrayAdapter;
import android.widget.ListView;
import android.widget.TextView;

import com.example.bankapp.Account;
import com.example.bankapp.MoneyFormatter;
import com.example.bankapp.R;
import com.example.bankapp.ServiceLocator;

import java.util.ArrayList;
import java.util.List;

public final class AccountsActivity extends Activity {
    private ListView listView;
    private TextView emptyView;
    private final List<Account> data = new ArrayList<>();
    private ArrayAdapter<String> adapter;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_accounts);

        listView = findViewById(R.id.accountsList);
        emptyView = findViewById(R.id.emptyText);

        adapter = new ArrayAdapter<>(this, android.R.layout.simple_list_item_1, new ArrayList<String>());
        listView.setAdapter(adapter);
        listView.setEmptyView(emptyView);

        listView.setOnItemClickListener(new AdapterView.OnItemClickListener() {
            @Override
            public void onItemClick(AdapterView<?> parent, View view, int position, long id) {
                Account a = data.get(position);
                Intent i = new Intent(AccountsActivity.this, AccountDetailActivity.class);
                i.putExtra(AccountDetailActivity.EXTRA_ACCOUNT_ID, a.id);
                startActivity(i);
            }
        });
    }

    @Override
    protected void onResume() {
        super.onResume();
        new LoadAccountsTask().execute();
    }

    private final class LoadAccountsTask extends AsyncTask<Void, Void, List<Account>> {
        @Override
        protected List<Account> doInBackground(Void... voids) {
            return ServiceLocator.get().accounts().getAll();
        }

        @Override
        protected void onPostExecute(List<Account> accounts) {
            data.clear();
            data.addAll(accounts);
            adapter.clear();
            for (Account a : accounts) {
                adapter.add(a.displayName + " • " + MoneyFormatter.formatMinor(a.currency, a.balanceMinor));
            }
            adapter.notifyDataSetChanged();
        }
    }
}

package com.example.bankapp.ui;

import android.app.Activity;
import android.app.AlertDialog;
import android.os.AsyncTask;
import android.os.Bundle;
import android.text.Editable;
import android.text.TextWatcher;
import android.view.View;
import android.widget.ArrayAdapter;
import android.widget.Button;
import android.widget.EditText;
import android.widget.Spinner;
import android.widget.TextView;

import com.example.bankapp.Account;
import com.example.bankapp.MoneyFormatter;
import com.example.bankapp.R;
import com.example.bankapp.ServiceLocator;
import com.example.bankapp.TransactionProcessor;

import java.util.ArrayList;
import java.util.List;

public final class AccountDetailActivity extends Activity {
    public static final String EXTRA_ACCOUNT_ID = "extra_account_id";

    private TextView title;
    private TextView balance;
    private Spinner toAccountSpinner;
    private EditText amountMinorInput;
    private EditText noteInput;
    private Button sendButton;

    private Account fromAccount;
    private final List<Account> allAccounts = new ArrayList<>();
    private ArrayAdapter<String> spinnerAdapter;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_account_detail);

        title = findViewById(R.id.accountTitle);
        balance = findViewById(R.id.accountBalance);
        toAccountSpinner = findViewById(R.id.toAccountSpinner);
        amountMinorInput = findViewById(R.id.amountMinorInput);
        noteInput = findViewById(R.id.noteInput);
        sendButton = findViewById(R.id.sendButton);

        spinnerAdapter = new ArrayAdapter<>(this, android.R.layout.simple_spinner_item, new ArrayList<String>());
        spinnerAdapter.setDropDownViewResource(android.R.layout.simple_spinner_dropdown_item);
        toAccountSpinner.setAdapter(spinnerAdapter);

        amountMinorInput.addTextChangedListener(new TextWatcher() {
            @Override public void beforeTextChanged(CharSequence s, int start, int count, int after) {}
            @Override public void onTextChanged(CharSequence s, int start, int before, int count) { updateButtonState(); }
            @Override public void afterTextChanged(Editable s) {}
        });

        sendButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                if (fromAccount == null) return;
                int pos = toAccountSpinner.getSelectedItemPosition();
                if (pos < 0 || pos >= allAccounts.size()) return;
                Account to = allAccounts.get(pos);
                String raw = amountMinorInput.getText().toString().trim();
                long amt;
                try {
                    amt = Long.parseLong(raw);
                } catch (Exception e) {
                    showMessage("Invalid amount");
                    return;
                }
                String note = noteInput.getText().toString();
                new TransferTask(fromAccount.id, to.id, amt, fromAccount.currency, note).execute();
            }
        });
    }

    @Override
    protected void onResume() {
        super.onResume();
        new LoadTask(getIntent().getStringExtra(EXTRA_ACCOUNT_ID)).execute();
    }

    private void bind(Account a) {
        title.setText(a.displayName);
        balance.setText(MoneyFormatter.formatMinor(a.currency, a.balanceMinor));
        updateButtonState();
    }

    private void updateButtonState() {
        boolean enabled = fromAccount != null && amountMinorInput.getText().toString().trim().length() > 0
                && toAccountSpinner.getSelectedItemPosition() >= 0;
        sendButton.setEnabled(enabled);
    }

    private void showMessage(String msg) {
        new AlertDialog.Builder(this)
                .setMessage(msg)
                .setPositiveButton(android.R.string.ok, null)
                .show();
    }

    private final class LoadTask extends AsyncTask<Void, Void, Object> {
        private final String accountId;

        LoadTask(String accountId) {
            this.accountId = accountId;
        }

        @Override
        protected Object doInBackground(Void... voids) {
            Account a = ServiceLocator.get().accounts().getById(accountId);
            List<Account> all = ServiceLocator.get().accounts().getAll();
            return new Object[]{a, all};
        }

        @Override
        @SuppressWarnings("unchecked")
        protected void onPostExecute(Object result) {
            Object[] arr = (Object[]) result;
            fromAccount = (Account) arr[0];
            List<Account> all = (List<Account>) arr[1];

            if (fromAccount == null) {
                showMessage("Account not found");
                finish();
                return;
            }

            allAccounts.clear();
            spinnerAdapter.clear();
            for (Account a : all) {
                if (!a.id.equals(fromAccount.id)) {
                    allAccounts.add(a);
                    spinnerAdapter.add(a.displayName);
                }
            }
            spinnerAdapter.notifyDataSetChanged();
            bind(fromAccount);
        }
    }

    private final class TransferTask extends AsyncTask<Void, Void, TransactionProcessor.Result> {
        private final String fromId;
        private final String toId;
        private final long amtMinor;
        private final String currency;
        private final String note;

        TransferTask(String fromId, String toId, long amtMinor, String currency, String note) {
            this.fromId = fromId;
            this.toId = toId;
            this.amtMinor = amtMinor;
            this.currency = currency;
            this.note = note;
        }

        @Override
        protected void onPreExecute() {
            sendButton.setEnabled(false);
        }

        @Override
        protected TransactionProcessor.Result doInBackground(Void... voids) {
            return ServiceLocator.get().processor().transfer(fromId, toId, amtMinor, currency, note);
        }

        @Override
        protected void onPostExecute(TransactionProcessor.Result r) {
            sendButton.setEnabled(true);
            if (!r.ok) {
                showMessage(r.error);
                return;
            }
            amountMinorInput.setText("");
            noteInput.setText("");
            new LoadTask(fromId).execute();
            showMessage("Transfer posted. ID: " + r.transactionId);
        }
    }
}

